using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests
    {
        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            using var service = new NotificationService();

            service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            var received = service.ReceiveNotification();
            Assert.NotNull(received);
            Assert.Equal("Student", received.EntityType);
            Assert.Equal("1", received.EntityId);
            Assert.Equal("CREATE", received.Operation);
            Assert.Contains("John Doe", received.Message);
            Assert.Equal("Admin", received.CreatedBy);
            Assert.False(received.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesEntityId()
        {
            using var service = new NotificationService();

            service.SendNotification("Course", "42", EntityOperation.UPDATE, "Teacher");

            var received = service.ReceiveNotification();
            Assert.NotNull(received);
            Assert.Contains("ID: 42", received.Message);
            Assert.Contains("updated", received.Message);
        }

        [Fact]
        public void SendNotification_WithNullUserName_DefaultsToSystem()
        {
            using var service = new NotificationService();

            service.SendNotification("Department", "1", "Math", EntityOperation.DELETE);

            var received = service.ReceiveNotification();
            Assert.NotNull(received);
            Assert.Equal("System", received.CreatedBy);
        }

        [Fact]
        public void SendNotification_CreateOperation_GeneratesCorrectMessage()
        {
            using var service = new NotificationService();

            service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "User");

            var received = service.ReceiveNotification();
            Assert.Contains("created", received.Message);
            Assert.Contains("Test Student", received.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
        {
            using var service = new NotificationService();

            service.SendNotification("Student", "1", "Test Student", EntityOperation.UPDATE, "User");

            var received = service.ReceiveNotification();
            Assert.Contains("updated", received.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
        {
            using var service = new NotificationService();

            service.SendNotification("Student", "1", "Test Student", EntityOperation.DELETE, "User");

            var received = service.ReceiveNotification();
            Assert.Contains("deleted", received.Message);
        }

        [Fact]
        public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
        {
            // Drain any existing messages from static queue
            using var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }

            var result = service.ReceiveNotification();
            Assert.Null(result);
        }

        [Fact]
        public void ReceiveNotification_ReturnsInFifoOrder()
        {
            using var service = new NotificationService();

            service.SendNotification("First", "1", "First", EntityOperation.CREATE, "User");
            service.SendNotification("Second", "2", "Second", EntityOperation.UPDATE, "User");

            var first = service.ReceiveNotification();
            var second = service.ReceiveNotification();

            Assert.Equal("First", first.EntityType);
            Assert.Equal("Second", second.EntityType);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            using var service = new NotificationService();

            var exception = Record.Exception(() => service.MarkAsRead(1));
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_SetsCreatedAtToCurrentTime()
        {
            using var service = new NotificationService();
            var before = System.DateTime.Now.AddSeconds(-1);

            service.SendNotification("Test", "1", "Test", EntityOperation.CREATE, "User");

            var received = service.ReceiveNotification();
            var after = System.DateTime.Now.AddSeconds(1);
            Assert.InRange(received.CreatedAt, before, after);
        }

        [Fact]
        public void SendNotification_SetsIsReadToFalse()
        {
            using var service = new NotificationService();

            service.SendNotification("Test", "1", "Test", EntityOperation.CREATE, "User");

            var received = service.ReceiveNotification();
            Assert.False(received.IsRead);
        }
    }
}

using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PaginatedListTests
    {
        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(1, result.First());
            Assert.Equal(10, result.Last());
        }

        [Fact]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(11, result.First());
            Assert.Equal(20, result.Last());
        }

        [Fact]
        public void Create_LastPage_ReturnRemainingItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.Equal(5, result.Count);
            Assert.Equal(21, result.First());
            Assert.Equal(25, result.Last());
        }

        [Fact]
        public void TotalPages_CalculatedCorrectly()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(3, result.TotalPages);
        }

        [Fact]
        public void TotalPages_ExactMultiple()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(2, result.TotalPages);
        }

        [Fact]
        public void PageIndex_SetCorrectly()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.Equal(3, result.PageIndex);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.True(result.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();

            var result = PaginatedList<int>.Create(source, 5, 10);

            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void HasNextPage_FirstPage_ReturnsTrue()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
        }

        [Fact]
        public void Constructor_SetsProperties()
        {
            var items = new List<int> { 1, 2, 3 };

            var result = new PaginatedList<int>(items, 30, 2, 10);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal(3, result.Count);
        }
    }
}

