        public void SendNotification_SetsCreatedAtToCurrentTime()
        {
            using var service = new NotificationService();
            var before = System.DateTime.Now.AddSeconds(-1);

            service.SendNotification("Test", "1", "Test", EntityOperation.CREATE, "User");

            var received = service.ReceiveNotification();
            var after = System.DateTime.Now.AddSeconds(1);
            Assert.InRange(received.CreatedAt, before, after);
        }

