{
    public class HomeControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly HomeController _controller;

        public HomeControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _controller = new HomeController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsView()
        {
            var result = _controller.Index();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_ReturnsViewWithEnrollmentStats()
        {
            var result = _controller.About() as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.NotNull(model);
            Assert.True(model.Count > 0);
        }

        [Fact]
        public void About_GroupsByEnrollmentDate()
        {
            var result = _controller.About() as ViewResult;
            var model = result.Model as List<EnrollmentDateGroup>;

            // Each group should have a unique date
            var dates = model.Select(g => g.EnrollmentDate).ToList();
            Assert.Equal(dates.Count, dates.Distinct().Count());
        }

        [Fact]
        public void About_CountsStudentsCorrectly()
        {
            var result = _controller.About() as ViewResult;
            var model = result.Model as List<EnrollmentDateGroup>;

            var totalStudents = model.Sum(g => g.StudentCount);
            Assert.Equal(3, totalStudents); // 3 seeded students
        }

        [Fact]
        public void Contact_ReturnsView()
        {
            var result = _controller.Contact() as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("Your contact page.", _controller.ViewBag.Message);
        }

        [Fact]
        public void Error_ReturnsView()
        {
            var result = _controller.Error();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Unauthorized_ReturnsViewWithMessage()
        {
            var result = _controller.Unauthorized() as ViewResult;

            Assert.NotNull(result);
            Assert.Contains("permission", (string)_controller.ViewBag.Message);
        }
    }
}
