        #region Edit POST

        [Fact]
        public void Edit_Post_ValidCourse_RedirectsToIndex()
        {
            var course = _context.Courses.Find(1050);
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updatedCourse = new Course
            {
                CourseID = 1050,
                Title = "Updated Chemistry",
                Credits = 4,
                DepartmentID = 3
            };

            var result = _controller.Edit(updatedCourse, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
