        public void Edit_Post_WithNewImage_UpdatesImagePath()
        {
            var course = _context.Courses.Find(1050);
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updatedCourse = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 3
            };

            var fileMock = CreateMockFormFile("new_image.jpg", "image/jpeg", 1024);

            _controller.Edit(updatedCourse, fileMock.Object);

            Assert.NotNull(updatedCourse.TeachingMaterialImagePath);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
