{"file_text": "using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class ModelValidationTests
    {
        private IList<ValidationResult> ValidateModel(object model)
        {
            var validationResults = new List<ValidationResult>();
            var ctx = new ValidationContext(model, null, null);
            Validator.TryValidateObject(model, ctx, validationResults, true);
            return validationResults;
        }

        #region Person / Student

        [Fact]
        public void Student_ValidModel_NoValidationErrors()
        {
            var student = new Student
            {
                FirstMidName = "John",
                LastName = "Doe",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var results = ValidateModel(student);

            Assert.Empty(results);
        }

        [Fact]
        public void Student_MissingLastName_HasValidationError()
        {
            var student = new Student
            {
                FirstMidName = "John",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var results = ValidateModel(student);

            Assert.Contains(results, r => r.MemberNames.Any(m => m == "LastName"));
        }

        [Fact]
        public void Student_MissingFirstName_HasValidationError()
        {
            var student = new Student
            {
                LastName = "Doe",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var results = ValidateModel(student);

            Assert.Contains(results, r => r.MemberNames.Any(m => m == "FirstMidName"));
        }

        [Fact]
        public void Student_LastNameTooLong_HasValidationError()
        {
            var student = new Student
            {
                FirstMidName = "John",
                LastName = new string('A', 51),
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var results = ValidateModel(student);

            Assert.Contains(results, r => r.MemberNames.Any(m => m == "LastName"));
        }

        [Fact]
        public void Student_FirstNameTooLong_HasValidationError()
        {
            var student = new Student
            {
                FirstMidName = new string('A', 51),
                LastName = "Doe",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var results = ValidateModel(student);

            Assert.Contains(results, r => r.MemberNames.Any(m => m == "FirstMidName"));
        }

        [Fact]
        public void Person_FullName_ReturnsCorrectFormat()
        {
            var student = new Student
            {
                FirstMidName = "John",
                LastName = "Doe"
            };

            Assert.Equal("Doe, John", student.FullName);
        }

        #endregion

        #region Instructor

        [Fact]
        public void Instructor_ValidModel_NoValidationErrors()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Jane",
                LastName = "Smith",
                HireDate = DateTime.Parse("2020-01-15")
            };

            var results = ValidateModel(instructor);

            Assert.Empty(results);
        }

        [Fact]
        public void Instructor_MissingLastName_HasValidationError()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Jane",
                HireDate = DateTime.Parse("2020-01-15")
            };

            var results = ValidateModel(instructor);

            Assert.Contains(results, r => r.MemberNames.Any(m => m == "LastName"));
        }

        [Fact]
        public void Instructor_FullName_ReturnsCorrectFormat()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Jane",
                LastName = "Smith"
            };

            Assert.Equal("Smith, Jane", instructor.FullName);
        }

        #endregion

        #region Course

        [Fact]
        public void Course_ValidModel_NoValidationErrors()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);

            Assert.Empty(results);
        }

        [Fact]
        public void Course_TitleTooShort_HasValidationError()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "AB",
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);

            Assert.Contains(results, r => r.MemberNames.Any(m => m == "Title"));
        }

        [Fact]
        public void Course_TitleTooLong_HasValidationError()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = new string('A', 51),
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);

            Assert.Contains(results, r => r.MemberNames.Any(m => m == "Title"));
        }

        [Fact]
        public void Course_CreditsOutOfRange_HasValidationError()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Chemistry",
                Credits = 6,
                DepartmentID = 1
            };

            var results = ValidateModel(course);

            Assert.Contains(results, r => r.MemberNames.Any(m => m == "Credits"));
        }

        [Fact]
        public void Course_NegativeCredits_HasValidationError()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Chemistry",
                Credits = -1,
                DepartmentID = 1
            };

            var results = ValidateModel(course);

            Assert.Contains(results, r => r.MemberNames.Any(m => m == "Credits"));
