        #endregion

        #region Department

        [Fact]
        public void Department_ValidModel_NoValidationErrors()
        {
            var department = new Department
            {
                Name = "Mathematics",
                Budget = 100000,
                StartDate = DateTime.Parse("2007-09-01")
            };

            var results = ValidateModel(department);

            Assert.Empty(results);
        }

        [Fact]
        public void Department_NameTooShort_HasValidationError()
        {
            var department = new Department
            {
                Name = "AB",
                Budget = 100000,
                StartDate = DateTime.Parse("2007-09-01")
            };

            var results = ValidateModel(department);

            Assert.Contains(results, r => r.MemberNames.Any(m => m == "Name"));
        }

        [Fact]
        public void Department_NameTooLong_HasValidationError()
        {
            var department = new Department
            {
                Name = new string('A', 51),
                Budget = 100000,
                StartDate = DateTime.Parse("2007-09-01")
            };

            var results = ValidateModel(department);

            Assert.Contains(results, r => r.MemberNames.Any(m => m == "Name"));
        }

        #endregion

        #region Enrollment

        [Fact]
        public void Enrollment_GradeCanBeNull()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1050,
                StudentID = 1,
                Grade = null
            };

            var results = ValidateModel(enrollment);

            Assert.Empty(results);
        }

        [Fact]
        public void Enrollment_AllGradesAreValid()
        {
            foreach (Grade grade in Enum.GetValues(typeof(Grade)))
            {
                var enrollment = new Enrollment
                {
                    EnrollmentID = 1,
                    CourseID = 1050,
                    StudentID = 1,
                    Grade = grade
                };

                var results = ValidateModel(enrollment);
                Assert.Empty(results);
            }
        }

        #endregion

        #region Notification

        [Fact]
        public void Notification_ValidModel_NoValidationErrors()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "New student created",
                CreatedAt = DateTime.Now
            };

            var results = ValidateModel(notification);

            Assert.Empty(results);
        }

        [Fact]
        public void Notification_MissingEntityType_HasValidationError()
        {
            var notification = new Notification
            {
                EntityId = "1",
                Operation = "CREATE",
                Message = "New student created",
                CreatedAt = DateTime.Now
            };

            var results = ValidateModel(notification);

            Assert.Contains(results, r => r.MemberNames.Any(m => m == "EntityType"));
        }

        [Fact]
        public void Notification_MissingMessage_HasValidationError()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                CreatedAt = DateTime.Now
