using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _controller = new DepartmentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as System.Collections.Generic.List<Department>;
            Assert.NotNull(model);
            Assert.Equal(3, model.Count);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", department.Name);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsView()
        {
            var result = _controller.Create();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Create_Get_SetsInstructorSelectList()
        {
            _controller.Create();

            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
        {
            var department = new Department
            {
                Name = "Physics",
                Budget = 200000,
                StartDate = DateTime.Parse("2023-09-01"),
                InstructorID = 1
            };

            var result = _controller.Create(department);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_Post_ValidDepartment_SavesDepartment()
        {
            var department = new Department
            {
                Name = "Physics",
                Budget = 200000,
                StartDate = DateTime.Parse("2023-09-01"),
                InstructorID = 1
            };

            _controller.Create(department);

            Assert.Contains(_context.Departments, d => d.Name == "Physics");
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department
            {
                Budget = 200000,
                StartDate = DateTime.Parse("2023-09-01")
            };

            var result = _controller.Create(department);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal(department, viewResult.Model);
        }

        [Fact]
        public void Create_Post_InvalidModelState_SetsInstructorSelectList()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department
            {
                Budget = 200000,
                StartDate = DateTime.Parse("2023-09-01"),
                InstructorID = 1
            };

            _controller.Create(department);

            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithDepartment()
        {
            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", department.Name);
        }

        [Fact]
        public void Edit_Get_ValidId_SetsInstructorSelectList()
        {
            _controller.Edit(1);

            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void Edit_Post_ValidDepartment_RedirectsToIndex()
        {
            var dept = _context.Departments.Find(1);
            _context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var department = new Department
            {
                DepartmentID = 1,
                Name = "Updated English",
                Budget = 400000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 1
            };

            var result = _controller.Edit(department);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department
            {
                DepartmentID = 1,
                Name = "",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 1
            };

            var result = _controller.Edit(department);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal(department, viewResult.Model);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithDepartment()
        {
            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", department.Name);
        }

        #endregion

        #region Delete POST

        [Fact]
        public void DeleteConfirmed_RemovesDepartmentAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Null(_context.Departments.Find(1));
        }

        [Fact]
        public void DeleteConfirmed_DepartmentActuallyRemoved()
        {
            var initialCount = _context.Departments.Count();

            _controller.DeleteConfirmed(1);

            Assert.Equal(initialCount - 1, _context.Departments.Count());
        }

        #endregion
    }
}

